request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  ?model ?modelName ?originalId ?normalizedId ?created ?exporter ?version
  WHERE {
    ?model a bboExt:Model .
    ?model tai:originalId ?originalId .
    FILTER(STR(?originalId) = "1ad939eef40c461dafae27f75a0586d3")
    OPTIONAL { ?model bbo:name ?modelName . }
    OPTIONAL { ?model tai:normalizedId ?normalizedId . }
    OPTIONAL { ?model tai:modelCreated ?created . }
    OPTIONAL { ?defs bboExt:exporter ?exporter . }
    OPTIONAL { ?defs bboExt:exporterVersion ?version . }
    OPTIONAL {
      ?defs tai:belongsTo ?model .
    }
  }
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  ?choreo ?choreoName ?orgId ?modelId
WHERE {
  ?model a bboExt:Model ;
         tai:originalId ?modelId ;
         tai:belongsTo ?org .
  FILTER(STR(?modelId) = "1ad939eef40c461dafae27f75a0586d3")
  OPTIONAL { ?org tai:organizationId ?orgId . }

  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .
  OPTIONAL { ?choreo bbo:name ?choreoName . }
}
LIMIT 25
